#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int *XORs = (int*)malloc((N * (N - 1)) / 2 * sizeof(int));
        int index = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                XORs[index++] = A[i] ^ A[j];
            }
        }
        qsort(XORs, (N * (N - 1)) / 2, sizeof(int), compare);
        for (int i = 0; i < K; i++) {
            printf("%d ", XORs[i]);
        }
        printf("\n");
        free(A);
        free(XORs);
    }
    return 0;
}

