const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];

const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const [N, K] = readline().split(' ').map(Number);
    const A = [];
    for (let i = 0; i < N; i++) {
        A.push(parseInt(readline()));
    }
    const XORs = [];
    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            XORs.push(A[i] ^ A[j]);
        }
    }
    XORs.sort((a, b) => a - b);
    console.log(XORs.slice(0, K).join(' '));
}

